   905вҶ’## 4.2.7 Route Utilization Service (NEW v2.1)
   906вҶ’
   907вҶ’### 4.2.7.1 Purpose
   908вҶ’
   909вҶ’Provide route-specific daily mileage rates for accurate long-term projections. Using fleet-wide averages can result in 60,000+ km projection error over 12 years.
   910вҶ’
   911вҶ’### 4.2.7.2 Implementation
   912вҶ’
   913вҶ’```typescript
   914вҶ’interface RouteUtilizationProfile {
   915вҶ’  id: string;
   916вҶ’  routeId: string;
   917вҶ’  effectiveDate: Date;
   918вҶ’  
   919вҶ’  weekdayKm: number;
   920вҶ’  saturdayKm?: number;
   921вҶ’  sundayKm?: number;
   922вҶ’  holidayKm?: number;
   923вҶ’  
   924вҶ’  peakSeasonMultiplier: number;
   925вҶ’  offPeakMultiplier: number;
   926вҶ’  
   927вҶ’  confidence: 'HIGH' | 'MEDIUM' | 'LOW' | 'ESTIMATED';
   928вҶ’}
   929вҶ’
   930вҶ’class RouteUtilizationService {
   931вҶ’  constructor(private db: Database) {}
   932вҶ’  
   933вҶ’  /**
   934вҶ’   * Get utilization profile for a route
   935вҶ’   */
   936вҶ’  async getProfile(routeId: string, asOfDate?: Date): Promise<RouteUtilizationProfile | null> {
   937вҶ’    const date = asOfDate || new Date();
   938вҶ’    
   939вҶ’    const profile = await this.db
   940вҶ’      .select()
   941вҶ’      .from(routeUtilizationProfiles)
   942вҶ’      .where(and(
   943вҶ’        eq(routeUtilizationProfiles.routeId, routeId),
   944вҶ’        lte(routeUtilizationProfiles.effectiveDate, date)
   945вҶ’      ))
   946вҶ’      .orderBy(desc(routeUtilizationProfiles.effectiveDate))
   947вҶ’      .limit(1);
   948вҶ’    
   949вҶ’    return profile[0] || null;
   950вҶ’  }
   951вҶ’  
   952вҶ’  /**
   953вҶ’   * Calculate expected daily km for a train based on typical route assignment
   954вҶ’   */
   955вҶ’  async calculateDailyRate(
   956вҶ’    trainId: string, 
   957вҶ’    targetDate: Date
   958вҶ’  ): Promise<{ dailyKm: number; source: string; confidence: string }> {
   959вҶ’    // 1. Check for explicit route assignment
   960вҶ’    const assignment = await this.getTypicalRouteAssignment(trainId);
   961вҶ’    
   962вҶ’    if (assignment) {
   963вҶ’      const profile = await this.getProfile(assignment.routeId, targetDate);
   964вҶ’      if (profile) {
   965вҶ’        const dayType = this.getDayType(targetDate);
   966вҶ’        const baseKm = this.getKmForDayType(profile, dayType);
   967вҶ’        const seasonalMultiplier = this.getSeasonalMultiplier(profile, targetDate);
   968вҶ’        
   969вҶ’        return {
   970вҶ’          dailyKm: Math.round(baseKm * seasonalMultiplier),
   971вҶ’          source: `route:${assignment.routeId}`,
   972вҶ’          confidence: profile.confidence
   973вҶ’        };
   974вҶ’      }
   975вҶ’    }
   976вҶ’    
   977вҶ’    // 2. Fall back to fleet average
   978вҶ’    const train = await this.db
   979вҶ’      .select({ fleetId: trains.fleetId })
   980вҶ’      .from(trains)
   981вҶ’      .where(eq(trains.id, trainId))
   982вҶ’      .limit(1);
   983вҶ’    
   984вҶ’    if (train[0]) {
   985вҶ’      const fleetAverage = await this.getFleetAverage(train[0].fleetId);
   986вҶ’      return {
   987вҶ’        dailyKm: fleetAverage,
   988вҶ’        source: 'fleet_average',
   989вҶ’        confidence: 'LOW'
   990вҶ’      };
   991вҶ’    }
   992вҶ’    
   993вҶ’    // 3. System default
   994вҶ’    return {
   995вҶ’      dailyKm: 250,  // Conservative default
   996вҶ’      source: 'system_default',
   997вҶ’      confidence: 'ESTIMATED'
   998вҶ’    };
   999вҶ’  }
  1000вҶ’  
  1001вҶ’  /**
  1002вҶ’   * Project mileage for a train over a time horizon
  1003вҶ’   */
  1004вҶ’  async projectMileage(
  1005вҶ’    trainId: string,
  1006вҶ’    startDate: Date,
  1007вҶ’    horizonDays: number
  1008вҶ’  ): Promise<{ date: Date; projectedKm: number; cumulativeKm: number }[]> {
  1009вҶ’    const train = await this.db
  1010вҶ’      .select()
  1011вҶ’      .from(trains)
  1012вҶ’      .where(eq(trains.id, trainId))
  1013вҶ’      .limit(1);
  1014вҶ’    
  1015вҶ’    if (!train[0]) {
  1016вҶ’      throw new NotFoundError(`Train ${trainId} not found`);
  1017вҶ’    }
  1018вҶ’    
  1019вҶ’    let cumulativeKm = train[0].currentMileageKm;
  1020вҶ’    const projections: { date: Date; projectedKm: number; cumulativeKm: number }[] = [];
  1021вҶ’    
  1022вҶ’    for (let day = 0; day < horizonDays; day++) {
  1023вҶ’      const targetDate = addDays(startDate, day);
  1024вҶ’      const { dailyKm } = await this.calculateDailyRate(trainId, targetDate);
  1025вҶ’      
  1026вҶ’      cumulativeKm += dailyKm;
  1027вҶ’      projections.push({
  1028вҶ’        date: targetDate,
  1029вҶ’        projectedKm: dailyKm,
  1030вҶ’        cumulativeKm
  1031вҶ’      });
  1032вҶ’    }
  1033вҶ’    
  1034вҶ’    return projections;
  1035вҶ’  }
  1036вҶ’  
  1037вҶ’  private async getTypicalRouteAssignment(trainId: string): Promise<{ routeId: string } | null> {
  1038вҶ’    // Look at recent run assignments to determine typical route
  1039вҶ’    const recentAssignments = await this.db
  1040вҶ’      .select({ routeId: runAssignments.routeId, count: count() })
  1041вҶ’      .from(runAssignments)
  1042вҶ’      .where(and(
  1043вҶ’        eq(runAssignments.trainId, trainId),
  1044вҶ’        gte(runAssignments.assignmentDate, addDays(new Date(), -30))
  1045вҶ’      ))
  1046вҶ’      .groupBy(runAssignments.routeId)
  1047вҶ’      .orderBy(desc(count()))
  1048вҶ’      .limit(1);
  1049вҶ’    
  1050вҶ’    return recentAssignments[0] || null;
  1051вҶ’  }
  1052вҶ’  
  1053вҶ’  private async getFleetAverage(fleetId: string): Promise<number> {
  1054вҶ’    // Calculate from recent mileage readings
  1055вҶ’    const result = await this.db
  1056вҶ’      .select({ avgDaily: avg(mileageReadings.dailyKm) })
  1057вҶ’      .from(mileageReadings)
  1058вҶ’      .innerJoin(trains, eq(mileageReadings.trainId, trains.id))
  1059вҶ’      .where(and(
  1060вҶ’        eq(trains.fleetId, fleetId),
  1061вҶ’        gte(mileageReadings.readingDate, addDays(new Date(), -30)),
  1062вҶ’        eq(mileageReadings.validationStatus, 'VALID')
  1063вҶ’      ));
  1064вҶ’    
  1065вҶ’    return Math.round(result[0]?.avgDaily || 250);
  1066вҶ’  }
  1067вҶ’  
  1068вҶ’  private getKmForDayType(profile: RouteUtilizationProfile, dayType: string): number {
  1069вҶ’    switch (dayType) {
  1070вҶ’      case 'SATURDAY': return profile.saturdayKm || profile.weekdayKm * 0.8;
  1071вҶ’      case 'SUNDAY': return profile.sundayKm || profile.weekdayKm * 0.7;
  1072вҶ’      case 'HOLIDAY': return profile.holidayKm || profile.weekdayKm * 0.6;
  1073вҶ’      default: return profile.weekdayKm;
  1074вҶ’    }
  1075вҶ’  }
  1076вҶ’  
  1077вҶ’  private getSeasonalMultiplier(profile: RouteUtilizationProfile, date: Date): number {
  1078вҶ’    // TODO: Integrate with season calendar
  1079вҶ’    const month = date.getMonth();
  1080вҶ’    // Peak season: CNY (Jan-Feb), School holidays (Jun, Nov-Dec)
  1081вҶ’    const peakMonths = [0, 1, 5, 10, 11];
  1082вҶ’    return peakMonths.includes(month) ? profile.peakSeasonMultiplier : profile.offPeakMultiplier;
  1083вҶ’  }
  1084вҶ’  
  1085вҶ’  private getDayType(date: Date): string {
  1086вҶ’    const dayOfWeek = date.getDay();
  1087вҶ’    if (dayOfWeek === 0) return 'SUNDAY';
  1088вҶ’    if (dayOfWeek === 6) return 'SATURDAY';
  1089вҶ’    return 'WEEKDAY';
  1090вҶ’  }
  1091вҶ’}
